183		archiveSpec := DefaultRegistry().Resolve(BeadsArchiveCollection)
184		archiveFile, archiveLock := archiveSpec.PathsUnder(s.Dir)
185		archiveBackend := NewJSONLBackend(s.Dir, archiveFile, archiveLock, s.LockWait)
186	
187		activeBeads, err := activeBackend.ReadAll()
188		if err != nil {
189			return stats, fmt.Errorf("bead: migrate-to-axon read active: %w", err)
190		}
191		archiveBeads, err := archiveBackend.ReadAll()
192		if err != nil {
193			return stats, fmt.Errorf("bead: migrate-to-axon read archive: %w", err)
194		}
195	
196		seen := make(map[string]bool, len(activeBeads))
197		merged := make([]Bead, 0, len(activeBeads)+len(archiveBeads))
198		for _, b := range activeBeads {
199			seen[b.ID] = true
200			merged = append(merged, b)
201		}
202		for _, b := range archiveBeads {
203			if seen[b.ID] {
204				continue
205			}
206			seen[b.ID] = true
207			merged = append(merged, b)
208		}
209	
210		for i := range merged {
211			stats.BeadsMigrated++
212			if hasInlineEvents(&merged[i]) {
213				stats.EventsMigrated += len(decodeBeadEvents(merged[i].Extra["events"]))
214			}
215		}
216	
217		axon := NewAxonBackend(s.Dir, s.LockWait)
218		if err := axon.Init(); err != nil {
219			return stats, fmt.Errorf("bead: migrate-to-axon init: %w", err)
220		}
221		if err := axon.WithLock(func() error {
222			return axon.WriteAll(merged)
223		}); err != nil {
224			return stats, fmt.Errorf("bead: migrate-to-axon write: %w", err)
225		}
226		return stats, nil
227	}
228	
229	// hasInlineEvents reports whether a bead carries any inline events that
230	// can still be externalized. An empty array counts as "no inline events"
231	// so a second migrate pass on an already-externalized bead is a no-op.
232	func hasInlineEvents(b *Bead) bool {
233		if b == nil || b.Extra == nil {
234			return false
235		}
236		raw, ok := b.Extra["events"]
237		if !ok {
238			return false
239		}
240		return len(decodeBeadEvents(raw)) > 0
241	}

